          <option value="鼠希人">鼠希人</option>
          <option value="兔希人">兔希人</option>
          <option value="鬼族">鬼族</option>
          <option value="精灵">精灵</option>
          <option value="吸血鬼">吸血鬼</option>
          <option value="智能构造体">智能构造体</option>
        </select>
      </div>
      <div class="form-group">
        <label>性别</label>
        <select id="gender">
          <option value="男">男</option>
          <option value="女">女</option>
        </select>
      </div>
      <div class="form-group">
        <label>年龄</label>
        <input type="number" id="age" value="25" min="10" max="120">
      </div>
      <div class="form-group full">
        <label>背景简述</label>
        <input type="text" id="bio" placeholder="一句话概括你的角色背景" value="新艾利都的普通市民，过着平凡的日常生活">
