<script>
const PRESETS = {
  resident: {
    type:'普通居民',name:'',race:'人类',gender:'男',age:25,
    bio:'新艾利都的普通市民，过着平凡的日常生活',
    ether:45,combat:'无',faction:'无',special:'无'
  },
  officer: {
    type:'治安官',name:'',race:'人类',gender:'男',age:28,
    bio:'新艾利都治安局的一名基层治安官，日常巡逻六分街及周边区域',
    ether:55,combat:'中',faction:'新艾利都治安局（N.E.P.S.）',special:'标准治安官训练、以太抑制装备使用'
  },
  raider: {
    type:'盗洞客',name:'',race:'猫希人',gender:'男',age:30,
    bio:'经验丰富的盗洞客，以探索空洞寻找值钱物资为生',
    ether:70,combat:'强',faction:'独立',special:'空洞生存经验、以骸战斗技巧、简易萝卜绘制'
  }
};

let currentPreset = 'resident';

function selectPreset(key) {
  currentPreset = key;
  document.querySelectorAll('.preset-btn').forEach(b => b.classList.remove('active'));
  document.querySelector(`[data-preset="${key}"]`).classList.add('active');
  const p = PRESETS[key];
  document.getElementById('name').value = p.name;
  document.getElementById('race').value = p.race;
  document.getElementById('gender').value = p.gender;
  document.getElementById('age').value = p.age;
  document.getElementById('bio').value = p.bio;
  document.getElementById('ether').value = p.ether;
  document.getElementById('combat').value = p.combat;
  document.getElementById('faction').value = p.faction;
  document.getElementById('special').value = p.special;
  updateOutput();
}

function updateOutput() {
  const data = {
    'protagonist.是否为法厄同': false,
    'character.角色类型': document.getElementById('name').value ? '自定义' : PRESETS[currentPreset].type,
    'character.角色姓名': document.getElementById('name').value || '(待填写)',
    'character.种族': document.getElementById('race').value,
    'character.性别': document.getElementById('gender').value,
    'character.年龄': parseInt(document.getElementById('age').value) || 25,
    'character.背景简述': document.getElementById('bio').value,
    'character.以太适应性': parseInt(document.getElementById('ether').value) || 50,
    'character.战斗能力': document.getElementById('combat').value,
    'character.所属势力': document.getElementById('faction').value,
    'character.特殊能力': document.getElementById('special').value || '无'
  };

  let yaml = '---\n';
  yaml += '# 非绳匠开局 · 角色创建面板\n';
  yaml += '# 复制此块到开场白文件顶部即可生效\n\n';
  yaml += 'protagonist.是否为法厄同: false\n';
  yaml += 'character.角色类型: "' + data['character.角色类型'] + '"\n';
  yaml += 'character.角色姓名: "' + data['character.角色姓名'] + '"\n';
  yaml += 'character.种族: "' + data['character.种族'] + '"\n';
  yaml += 'character.性别: "' + data['character.性别'] + '"\n';
  yaml += 'character.年龄: ' + data['character.年龄'] + '\n';
  yaml += 'character.背景简述: "' + data['character.背景简述'] + '"\n';
  yaml += 'character.以太适应性: ' + data['character.以太适应性'] + '\n';
  yaml += 'character.战斗能力: "' + data['character.战斗能力'] + '"\n';
  yaml += 'character.所属势力: "' + data['character.所属势力'] + '"\n';
  yaml += 'character.特殊能力: "' + data['character.特殊能力'] + '"\n';
  yaml += '---\n\n';
  yaml += '# 选择对应的开场白文件：\n';
  yaml += '# 4-普通居民.txt | 5-治安官.txt | 6-盗洞客.txt\n';

  document.getElementById('output').value = yaml;
}

function copyOutput() {
  const ta = document.getElementById('output');
  ta.select();
  ta.setSelectionRange(0, 99999);
  navigator.clipboard.writeText(ta.value).then(() => {
    const btn = document.getElementById('copyBtn');
    btn.textContent = '✅ 已复制';
    btn.classList.add('copied');
    setTimeout(() => { btn.textContent = '📋 复制'; btn.classList.remove('copied'); }, 1500);
  });
}

// Bind form changes
document.querySelectorAll('#form input, #form select').forEach(el => {
  el.addEventListener('input', updateOutput);
  el.addEventListener('change', updateOutput);
});

// Bind preset buttons
document.querySelectorAll('.preset-btn').forEach(btn => {
  btn.addEventListener('click', () => selectPreset(btn.dataset.preset));
});

// Init
selectPreset('resident');
</script>
</body>
</html>
