<style>
:root{
  --bg:#0f1119;--card:#161b2a;--border:#1e2d50;--text:#c8d6e5;
  --muted:#6a7d99;--gold:#f0c040;--blue:#4fc3f7;--purple:#ab47bc;--green:#66bb6a;--orange:#ffa726;--pink:#ec407a;--danger:#ef5350
}
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:'Segoe UI','Microsoft YaHei',sans-serif;background:#0a0b12;color:var(--text);min-height:100vh;display:flex;justify-content:center;padding:16px}
.container{max-width:700px;width:100%}
.header{text-align:center;padding:18px 0 12px}
.header h1{font-size:20px;color:var(--gold)}
.header p{color:var(--muted);font-size:12px;margin-top:4px}
.tabs{display:flex;flex-wrap:wrap;gap:4px;margin-bottom:12px;background:var(--card);border-radius:10px;padding:6px;border:1px solid var(--border)}
.tab-btn{flex:1;min-width:48px;padding:8px 4px;text-align:center;cursor:pointer;font-size:11px;font-weight:600;border-radius:8px;background:transparent;color:var(--muted);border:none;transition:all .2s}
.tab-btn:hover{background:rgba(255,255,255,.05);color:var(--text)}
.tab-btn.active{background:rgba(255,255,255,.1);color:var(--gold)}
.tab-panel{display:none;animation:fadeIn .3s ease}.tab-panel.active{display:block}
@keyframes fadeIn{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
.card{background:var(--card);border-radius:12px;padding:16px;margin-bottom:10px;border:1px solid var(--border)}
.card h3{font-size:13px;margin-bottom:10px;padding-bottom:6px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:6px}
.card h3 .dot{width:8px;height:8px;border-radius:50%;display:inline-block}
.form-row{margin-bottom:10px;display:flex;align-items:center;gap:10px}
.form-row label{font-size:12px;color:var(--muted);min-width:72px;text-align:right}
.form-row .val{flex:1;font-size:13px;font-weight:600;color:var(--text)}
.bar-wrap{margin-bottom:12px}.bar-info{display:flex;justify-content:space-between;font-size:11px;margin-bottom:4px}.bar-bg{height:8px;background:rgba(255,255,255,.05);border-radius:4px;overflow:hidden}.bar-fill{height:100%;border-radius:4px;transition:width .5s}
.faction-list .fr{display:flex;align-items:center;gap:8px;margin-bottom:8px}
.faction-list .fr label{font-size:12px;width:90px;color:var(--muted)}
.faction-list .fr input{flex:1;accent-color:var(--green)}
.faction-list .fr .fr-val{font-size:12px;width:36px;text-align:right;color:var(--muted)}
.npc-card-w{border:1px solid var(--border);border-radius:10px;overflow:hidden;margin-bottom:12px;background:var(--card);position:relative;transition:all .3s}
.npc-card-w:hover{border-color:var(--gold)}
.npc-card-w .npc-bg{position:absolute;inset:0;background-size:cover;background-position:center;opacity:.15;z-index:0}
.npc-head,.npc-body{position:relative;z-index:1}
.npc-head{padding:14px 16px;display:flex;justify-content:space-between;align-items:center;cursor:pointer;border-bottom:1px solid transparent;transition:all .2s}
.npc-head:hover{background:rgba(255,255,255,.04)}
.npc-head.open{border-bottom-color:var(--border)}
.npc-name{font-weight:700;font-size:15px;color:var(--text);display:flex;align-items:center;gap:8px}
.npc-badge{font-size:11px;color:var(--muted);font-weight:400}
.npc-actions{display:flex;gap:8px}
.action-icon{width:30px;height:30px;border-radius:50%;background:rgba(22,27,42,.8);border:1px solid var(--border);display:flex;justify-content:center;align-items:center;font-size:13px;cursor:pointer;transition:all .3s;color:var(--muted)}
.action-icon:hover{transform:scale(1.1);color:var(--gold);border-color:var(--gold)}
.npc-body{display:none;padding:16px}.npc-body.open{display:block;animation:fadeIn .3s ease}
.ns-title{font-size:13px;font-weight:700;color:var(--gold);margin:14px 0 10px 0;display:flex;align-items:center;gap:6px}
.ns-title::before{content:'⚡';font-size:11px}.ns-title.pink{color:var(--pink)}.ns-title.pink::before{content:'🌸'}
.kv-row{display:flex;justify-content:space-between;font-size:12px;margin-bottom:6px;padding-bottom:4px;border-bottom:1px dashed rgba(255,255,255,.04)}.kv-row:last-child{border-bottom:none;margin-bottom:0;padding-bottom:0}
.kv-v{font-weight:600;text-align:right;max-width:70%;color:var(--text)}
.npc-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(100px,1fr));gap:10px;margin-bottom:14px}
.npc-g-card{padding:10px;background:rgba(255,255,255,.02);border:1px solid var(--border);border-radius:8px}
.npc-g-label{font-size:10px;color:var(--muted);display:block;margin-bottom:3px;text-transform:uppercase;font-weight:600}
.npc-g-val{font-size:12px;font-weight:700;color:var(--text)}
.text-block{padding:14px;margin-bottom:14px;background:rgba(255,255,255,.02);border:1px solid var(--border);border-radius:8px}.text-block .kv-row:last-child{border:none;margin:0;padding:0}
.footer{text-align:center;padding:12px;color:var(--muted);font-size:10px}
.nodata{text-align:center;color:var(--muted);padding:20px;font-size:12px}
</style>
</head>
<body>
<div class="container">
